<style>
.los{--line:rgba(119,157,194,.18);--panel:rgba(5,18,32,.97);display:grid;gap:.55rem;color:#edf7ff;font-size:.76rem}.los-head,.los-panel,.los-kpi,.los-card{border:1px solid var(--line);border-radius:7px;background:linear-gradient(145deg,rgba(9,28,45,.98),rgba(3,14,27,.98));box-shadow:0 16px 42px rgba(0,0,0,.2)}.los-head{display:flex;align-items:center;justify-content:space-between;gap:1rem;padding:.7rem .8rem}.los-head h1{font-size:1.25rem;font-weight:950}.los-head p,.los-muted{color:#829ab4}.los-nav{display:flex;flex-wrap:wrap;gap:.3rem}.los-nav a,.los-action{border:1px solid rgba(44,225,157,.3);border-radius:4px;padding:.38rem .5rem;background:#0b2738;color:#e1fff3;font-size:.57rem;font-weight:850}.los-nav a:focus-visible,.los-action:focus-visible,.los button:focus-visible{outline:2px solid #3ce6a2;outline-offset:2px}.los-kpis{display:grid;grid-template-columns:repeat(4,1fr);gap:.45rem}.los-kpi{padding:.55rem .62rem}.los-kpi span,.los-label{color:#36e69c;font-size:.51rem;font-weight:950;text-transform:uppercase}.los-kpi strong{display:block;margin-top:.28rem;font-size:1.1rem}.los-panel{overflow:hidden}.los-panel>header{display:flex;justify-content:space-between;gap:.5rem;border-bottom:1px solid var(--line);padding:.55rem .62rem;background:rgba(11,33,52,.62)}.los-panel h2{font-size:.72rem;font-weight:900}.los-list{display:grid;max-height:70vh;overflow:auto}.los-row,.los-card{display:grid;gap:.22rem;border-bottom:1px solid var(--line);padding:.55rem .62rem;text-align:left}.los-row:hover,.los-row.is-active{background:rgba(44,228,156,.075)}.los-row strong,.los-card strong{font-size:.65rem}.los-row span,.los-card span,.los-card p{color:#7891ad;font-size:.53rem}.los-grid{display:grid;grid-template-columns:18rem minmax(30rem,1fr) 20rem;gap:.5rem;align-items:start}.los-form{display:grid;gap:.4rem;padding:.55rem}.los-form label{display:grid;gap:.14rem;color:#819ab5;font-size:.52rem}.los-form input,.los-form select,.los-form textarea{border:1px solid var(--line);border-radius:4px;padding:.38rem;background:#061421;color:#edf7ff}.los-form button{border:1px solid rgba(44,225,157,.3);border-radius:4px;padding:.4rem;background:#0a7758;color:#fff;font-weight:850}.los-details{display:grid;padding:.5rem}.los-details div{display:flex;justify-content:space-between;gap:.5rem;border-bottom:1px solid rgba(119,157,194,.1);padding:.32rem 0}.los-details dt{color:#7891ad}.los-details dd{text-align:right}.los-board{display:grid;grid-template-columns:repeat(6,minmax(15rem,1fr));gap:.45rem;overflow-x:auto;padding-bottom:.5rem}.los-column{min-height:30rem}.los-column-list{display:grid;gap:.38rem;padding:.4rem}.los-card{position:relative;animation:losLive 4s ease-in-out infinite}.los-flow{display:flex;align-items:stretch;gap:.35rem;overflow-x:auto;padding:.75rem}.los-node{min-width:10rem;border:1px solid var(--line);border-radius:6px;padding:.6rem;background:#071a2b}.los-arrow{align-self:center;color:#3ee4a0;font-size:1rem}.los-map{height:31rem;background:#061421}.los-empty{padding:1.5rem;color:#829ab4;text-align:center}@keyframes losLive{50%{border-color:rgba(44,228,156,.34)}}@media(prefers-reduced-motion:reduce){.los *{animation:none!important;transition:none!important}}@media(max-width:1100px){.los-grid{grid-template-columns:1fr}.los-kpis{grid-template-columns:repeat(2,1fr)}}@media(max-width:600px){.los-head{align-items:start;flex-direction:column}.los-kpis{grid-template-columns:1fr}}
